mapper.select:
SELECT t.topic_id AS topicId, t.topic_title AS topicTitle, t.topic_category AS topicCategory, CASE t.topic_category WHEN 1 THEN '高职升本' WHEN 2 THEN '3+1' WHEN 3 THEN '实验班' ELSE '未知' END AS topicCategoryDesc, t.topic_type AS topicType, CASE t.topic_type WHEN 1 THEN '设计' WHEN 2 THEN '论文' ELSE '未知' END AS topicTypeDesc, t.topic_source AS topicSource, CASE t.topic_source WHEN 1 THEN '校内' WHEN 2 THEN '校外(协同开发)' ELSE '未知' END AS topicSourceDesc, e.enterprise_name AS enterpriseName, t.major_id AS majorId, mi.major_name AS majorName, t.guidance_direction AS guidanceDirection, u.real_name AS creatorName, t.content_summary AS contentSummary, IFNULL(sc.selected_count, 0) AS selectedCount, IF(ms.selection_id IS NOT NULL, TRUE, FALSE) AS alreadyApplied FROM topic_info t LEFT JOIN enterprise_info e ON t.enterprise_id = e.enterprise_id LEFT JOIN major_info mi ON t.major_id = mi.major_id AND mi.deleted = 0 LEFT JOIN user_info u ON t.creator_id = u.user_id LEFT JOIN ( SELECT topic_id, COUNT(*) AS selected_count FROM topic_selection WHERE deleted = 0 AND selection_status IN (0, 1) GROUP BY topic_id ) sc ON sc.topic_id = t.topic_id LEFT JOIN ( SELECT selection_id, topic_id FROM topic_selection WHERE deleted = 0 AND student_id = #{studentId} AND selection_status IN (0, 1) ) ms ON ms.topic_id = t.topic_id WHERE t.deleted = 0 AND t.review_status = 6
AND t.major_id = #{majorId}
AND t.topic_category = #{topicCategory}
AND t.guidance_direction LIKE CONCAT('%', #{guidanceDirection}, '%')
AND t.topic_title LIKE CONCAT('%', #{topicTitle}, '%')
ORDER BY t.create_time DESC
